// Send via ARQ (blocks until acknowledged) _, err =
client.StartResendingEncryptedMessage( nil, // readCap (nil for
writes) writeCap, nil, // messageBoxIndex (nil for writes) nil, //
replyIndex envDesc, ciphertext, envHash, ) if err != nil {
