lang="rust" >}} // Encrypt the message let result =
client.encrypt_write( b"hello", &write_cap,
&current_index, ).await?;

// Send via ARQ (blocks until acknowledged)
client.start_resending_encrypted_message( None, // read_cap (None
for writes) Some(&write_cap), None, // message_box_index None,
// reply_index &result.envelope_descriptor,
&result.message_ciphertext, &result.envelope_hash,
).await?;

// Advance the index for the next write current_index =
result.next_message_box_index; {{< /tab >}} {{< tab
header="Python" lang="python" >}}

// Send via ARQ (blocks until the message is retrieved) result,
err := client.StartResendingEncryptedMessage( readCap, nil, //
writeCap (nil for reads) nil, // messageBoxIndex nil, //
replyIndex envDesc, ciphertext, envHash, ) if err != nil {
log.Fatal(err) }

// Send via ARQ (blocks until the message is retrieved) let result
= client.start_resending_encrypted_message( Some(&read_cap),
None, // write_cap (None for reads) None, // message_box_index
None, // reply_index &read_result.envelope_descriptor,
&read_result.message_ciphertext,
&read_result.envelope_hash, ).await?;

let plaintext = result.plaintext; // Advance the index for the
next read current_index = read_result.next_message_box_index;
{{< /tab >}} {{< tab header="Python"
lang="python" >}}

// Send each tombstone for _, envelope := range result.Envelopes {
_, err = client.StartResendingEncryptedMessage( nil, writeCap,
nil, nil, envelope.EnvelopeDescriptor, envelope.MessageCiphertext,
envelope.EnvelopeHash, ) if err != nil { log.Fatal(err) } } //
result.Next is the index after the last tombstoned box {{< /tab
>}} {{< tab header="Rust" lang="rust"
