client.start_resending_encrypted_message( None,
Some(&write_cap), None, None,
&envelope.envelope_descriptor,
&envelope.message_ciphertext, &envelope.envelope_hash,
).await?; } // result.next is the index after the last tombstoned
box {{< /tab >}} {{< tab header="Python"
lang="python" >}}

// Create temporary channel tempSeed := make([]byte, 32)
rand.Reader.Read(tempSeed) tempWriteCap, _, tempFirstIndex, err :=
client.NewKeypair(tempSeed) if err != nil { log.Fatal(err) }

// Pack payload into copy stream elements envelopes, _, err :=
client.CreateCourierEnvelopesFromPayload( payload, destWriteCap,
destFirstIndex, true, // isStart true, // isLast ) if err != nil {
log.Fatal(err) }

// Write each element to the temporary channel tempIndex :=
tempFirstIndex for _, chunk := range envelopes { ciphertext,
envDesc, envHash, nextIdx, err := client.EncryptWrite( chunk,
tempWriteCap, tempIndex, ) if err != nil { log.Fatal(err) } _, err
= client.StartResendingEncryptedMessage( nil, tempWriteCap, nil,
nil, envDesc, ciphertext, envHash, ) if err != nil {
log.Fatal(err) } tempIndex = nextIdx }

// Send the copy command (blocks until courier acknowledges) err =
client.StartResendingCopyCommand(tempWriteCap) if err != nil {
log.Fatal(err) }

// Share destReadCap and destFirstIndex with the reader {{<
