lang="rust" >}} // Create destination channel let
dest_seed: [u8; 32] = rand::random(); let dest =
client.new_keypair(&dest_seed).await?;

// Create temporary channel let temp_seed: [u8; 32] =
rand::random(); let temp =
client.new_keypair(&temp_seed).await?;

// Pack payload into copy stream elements let envelopes_result =
client.create_courier_envelopes_from_payload( &payload,
&dest.write_cap, &dest.first_index, true, // is_start
true, // is_last ).await?;

// Write each element to the temporary channel let mut temp_index
= temp.first_index.clone(); for chunk in
&envelopes_result.envelopes { let write_result =
client.encrypt_write( chunk, &temp.write_cap, &temp_index,
).await?; client.start_resending_encrypted_message( None,
Some(&temp.write_cap), None, None,
&write_result.envelope_descriptor,
&write_result.message_ciphertext,
&write_result.envelope_hash, ).await?; temp_index =
write_result.next_message_box_index; }

// Send the copy command (blocks until courier acknowledges)
client.start_resending_copy_command(&temp.write_cap, None,
None).await?;

// Share dest.read_cap and dest.first_index with the reader {{<
