// Pack multiple payloads destinations :=
[]thin.DestinationPayload{ {Payload: payload1, WriteCap:
dest1WriteCap, StartIndex: dest1Index}, {Payload: payload2,
WriteCap: dest2WriteCap, StartIndex: dest2Index}, }

result, err := client.CreateCourierEnvelopesFromMultiPayload(
destinations, true, // isStart true, // isLast nil, // buffer (nil
for first call) ) if err != nil { log.Fatal(err) }

// Write envelopes to temporary channel tempIndex :=
tempFirstIndex for _, chunk := range result.Envelopes {
ciphertext, envDesc, envHash, nextIdx, err := client.EncryptWrite(
chunk, tempWriteCap, tempIndex, ) if err != nil { log.Fatal(err) }
_, err = client.StartResendingEncryptedMessage( nil, tempWriteCap,
nil, nil, envDesc, ciphertext, envHash, ) if err != nil {
log.Fatal(err) } tempIndex = nextIdx }

// Send copy command err =
client.StartResendingCopyCommand(tempWriteCap) {{< /tab >}}
{{< tab header="Rust" lang="rust" >}} //
Create destination channels let dest1 =
client.new_keypair(&seed1).await?; let dest2 =
client.new_keypair(&seed2).await?;

// Pack multiple payloads let destinations = vec![
(&payload1[..], &dest1.write_cap[..],
&dest1.first_index[..]), (&payload2[..],
&dest2.write_cap[..], &dest2.first_index[..]), ];

let result = client.create_courier_envelopes_from_multi_payload(
destinations, true, // is_start true, // is_last None, // buffer
(None for first call) ).await?;

// Write envelopes to temporary channel let mut temp_index =
temp.first_index.clone(); for chunk in &result.envelopes { let
write_result = client.encrypt_write( chunk, &temp.write_cap,
&temp_index, ).await?;
client.start_resending_encrypted_message( None,
Some(&temp.write_cap), None, None,
&write_result.envelope_descriptor,
&write_result.message_ciphertext,
&write_result.envelope_hash, ).await?; temp_index =
write_result.next_message_box_index; }

// Send copy command
client.start_resending_copy_command(&temp.write_cap, None,
None).await?; {{< /tab >}} {{< tab
header="Python" lang="python" >}}

// First batch let result1 =
client.create_courier_envelopes_from_multi_payload(
batch1_destinations, true, // is_start false, // is_last buffer,
).await?; // Write result1.envelopes to temp channel... buffer =
result1.buffer; // save for next call

// Second batch (final) let result2 =
client.create_courier_envelopes_from_multi_payload(
batch2_destinations, false, // is_start true, // is_last buffer,
).await?; // Write result2.envelopes to temp channel... {{<
