lang="python" >}} buffer = None # None on first call

// Create tombstone copy stream elements envelopes, nextBuffer,
nextDestIndex, err :=
client.CreateCourierEnvelopesFromTombstoneRange( destWriteCap,
destStartIndex, 10, // tombstone 10 boxes true, // isStart true,
// isLast nil, // buffer ) if err != nil { log.Fatal(err) }

// Write to temporary channel tempIndex := tempFirstIndex for _,
chunk := range envelopes { ciphertext, envDesc, envHash, nextIdx,
err := client.EncryptWrite( chunk, tempWriteCap, tempIndex, ) if
err != nil { log.Fatal(err) } _, err =
client.StartResendingEncryptedMessage( nil, tempWriteCap, nil,
nil, envDesc, ciphertext, envHash, ) if err != nil {
log.Fatal(err) } tempIndex = nextIdx }

// Send copy command err =
