let temp = client.new_keypair(&temp_seed).await?;

// Create tombstone copy stream elements let result =
client.create_courier_envelopes_from_tombstone_range(
&dest_write_cap, &dest_start_index, 10, // tombstone 10
boxes true, // is_start true, // is_last None, // buffer ).await?;

// Write to temporary channel let mut temp_index =
temp.first_index.clone(); for chunk in &result.envelopes { let
write_result = client.encrypt_write( chunk, &temp.write_cap,
&temp_index, ).await?;
client.start_resending_encrypted_message( None,
