&write_result.envelope_descriptor,
&write_result.message_ciphertext,
&write_result.envelope_hash, ).await?; temp_index =
write_result.next_message_box_index; }

// Cancel a copy command use blake2::{Blake2b, Digest}; use
digest::consts::U32; let write_cap_hash: [u8; 32] =
Blake2b::::digest(&temp_write_cap).into();
client.cancel_resending_copy_command(&write_cap_hash).await?;
